+.emoji-picker {
+    position: absolute;
+    right: 8px;
+    top: 32px;
+    background: #fff;
+    border: 1px solid #ddd;
+    border-radius: 8px;
+    padding: 6px;
+    display: flex;
+    gap: 2px;
+    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
+    z-index: 3;
+}
+
+.emoji-option {
+    background: none;
+    border: none;
+    font-size: 1.3rem;
+    cursor: pointer;
+    padding: 4px 6px;
+    border-radius: 4px;
+    line-height: 1;
+}
+
+.emoji-option:hover {
+    background: #f0f0f0;
+}
+
+/* ── Compose area ── */
+.compose-area {
+    display: flex;
+    gap: 8px;
+    padding: 12px 20px;
+    border-top: 1px solid #e8e8e8;
+    flex-shrink: 0;
+}
+
+.compose-input {
+    flex: 1;
+    border: 1px solid #ccc;
+    border-radius: 6px;
+    padding: 8px 12px;
+    font-size: 0.93rem;
+    resize: none;
+    font-family: inherit;
+    outline: none;
+    transition: border-color 0.15s;
+}
+
+.compose-input:focus {
+    border-color: #1264a3;
+}
+
+.send-btn {
+    background: #007a5a;
+    color: #fff;
+    border: none;
+    border-radius: 6px;
+    padding: 8px 20px;
+    font-weight: 600;
+    font-size: 0.9rem;
+    cursor: pointer;
+    align-self: flex-end;
+    transition: background 0.15s;
+}
+
+.send-btn:hover:not(:disabled) {
+    background: #005e44;
+}
+
+.send-btn:disabled {
+    opacity: 0.5;
+    cursor: not-allowed;
+}
+
+/* ── Thread panel ── */
+.chat-thread {
+    width: 25%;
+    min-width: 280px;
+    border-left: 1px solid #e8e8e8;
+    background: #fff;
+    display: flex;
+    flex-direction: column;
+}
+
+.thread-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    padding: 12px 16px;
+    border-bottom: 1px solid #e8e8e8;
+    flex-shrink: 0;
+}
+
+.thread-header h3 {
+    margin: 0;
+    font-size: 1.05rem;
+}
+
+.close-btn {
+    background: none;
+    border: none;
+    font-size: 1.1rem;
+    cursor: pointer;
+    color: #666;
+    padding: 4px 8px;
+    border-radius: 4px;
+}
+
+.close-btn:hover {
+    background: #f0f0f0;
+    color: #333;
+}
+
+.thread-root-quote {
+    padding: 12px 16px;
+    border-bottom: 1px solid #e8e8e8;
+    background: #fafafa;
+    flex-shrink: 0;
+}
+
+.thread-root-quote strong {
+    font-size: 0.92rem;
+}
+
+.thread-root-quote p {
+    margin: 4px 0 0;
+    font-size: 0.9rem;
+    color: #444;
+}
+
+.thread-replies {
+    flex: 1;
+    overflow-y: auto;
+    padding: 12px 16px;
+}
+
+.thread-replies .message-bubble {
+    padding: 6px 0;
+}
