@page "/chat"
@rendermode InteractiveServer
@using sv_19629a0ed9df4eb2824df3e78772db4b.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="chat-sidebar">
        <h3 class="sidebar-title">Channels</h3>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-header-row">
                            <span class="channel-name"># @channel.Name</span>
                            @if (channel.UnreadCount > 0)
                            {
                                <span class="unread-badge">@channel.UnreadCount</span>
                            }
                        </div>
                        <span class="channel-desc">@Truncate(channel.Description, 50)</span>
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="chat-main @(_threadOpen ? "" : "chat-main--full")">
        @if (_activeChannel is not null)
        {
            <header class="main-header">
                <h2># @_activeChannel.Name</h2>
                <p>@_activeChannel.Description</p>
            </header>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => { if (_hoveredMessageId == msg.Id) _hoveredMessageId = null; }">
                            <div class="message-bubble">
                                <div class="message-meta">
                                    <strong class="message-author">@msg.Author</strong>
                                    <time class="message-time">@FormatRelativeTime(msg.SentAt)</time>
                                </div>
                                <p class="message-content">@msg.Content</p>

                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reaction-row">
                                        @foreach (var r in msg.Reactions)
                                        {
                                            <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                    @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                                @r.Emoji @r.Users.Count
                                            </button>
                                        }
                                    </div>
                                }

                                @if (_threadSummaries.TryGetValue(msg.Id, out var ts))
                                {
                                    <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                        @ts.ReplyCount @(ts.ReplyCount == 1 ? "reply" : "replies")
                                    </button>
                                }
                            </div>

                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">💬 Reply</button>
                                    <button class="action-btn" title="Add reaction"
                                            @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                                </div>
                            }

                            @if (_emojiPickerMessageId == msg.Id)
                            {
                                <div class="emoji-picker">
                                    @foreach (var emoji in _commonEmojis)
                                    {
                                        <button class="emoji-option"
                                                @onclick="() => PickEmojiAsync(msg.Id, emoji)">@emoji</button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="compose-area">
                <textarea class="compose-input" placeholder="Type a message…" @bind="_newMessage"
                          @onkeydown="OnComposeKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessage)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="chat-thread">
            <header class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </header>

            <div class="thread-root-quote">
                <strong>@_threadRootMessage.Author</strong>
                <p>@_threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @if (_threadReplies is not null)
                {
                    @foreach (var reply in _threadReplies)
                    {
                        <div class="message-bubble">
                            <div class="message-meta">
                                <strong class="message-author">@reply.Author</strong>
                                <time class="message-time">@FormatRelativeTime(reply.SentAt)</time>
                            </div>
                            <p class="message-content">@reply.Content</p>
                        </div>
                    }
                }
            </div>

            <div class="compose-area">
                <textarea class="compose-input" placeholder="Reply in thread…" @bind="_threadReply"
                          @onkeydown="OnThreadReplyKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_threadReply)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;

    private List<Message>? _messages;
    private int _skip;
    private bool _loadingMore;
    private bool _allLoaded;

    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private string _threadReply = string.Empty;

    private string _newMessage = string.Empty;
    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    // ── Channel selection ──

    private async Task SelectChannelAsync(Channel channel)
    {
        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _skip = 0;
        _allLoaded = false;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _skip = _messages.Count;
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh the channel list to clear the unread badge
        _channels = await ChatService.GetChannelsAsync();

        CloseThread();
    }

    // ── Message loading (infinite scroll up) ──

    private async Task OnMessageListScroll()
    {
        if (_loadingMore || _allLoaded || _activeChannelId is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop > 50) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count == 0)
        {
            _allLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _skip += older.Count;
            BuildThreadSummaries();
        }

        _loadingMore = false;
    }

    // ── Sending messages ──

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
        _messages ??= [];
        _messages.Add(msg);
        _skip++;
        _newMessage = string.Empty;
    }

    private async Task OnComposeKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ── Reactions ──

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task PickEmojiAsync(int messageId, string emoji)
    {
        _emojiPickerMessageId = null;
        await ReactAsync(messageId, emoji);
    }

    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);

        // Re-fetch the channel messages to reflect updated reactions
        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _skip);
        }
    }

    // ── Threads ──

    private void BuildThreadSummaries()
    {
        _threadSummaries.Clear();
        if (_messages is null) return;

        var rootIds = _messages.Where(m => m.ReplyToId is null).Select(m => m.Id).ToHashSet();
        var replies = _messages.Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value));

        foreach (var group in replies.GroupBy(r => r.ReplyToId!.Value))
        {
            _threadSummaries[group.Key] = new ThreadSummary(group.Key, group.Count(), group.Max(r => r.SentAt));
        }
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadReply = string.Empty;
        _threadOpen = true;
        _emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReply) || _threadRootMessage is null || _activeChannelId is null) return;
        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReply.Trim(), _threadRootMessage.Id);
        _threadReplies ??= [];
        _threadReplies.Add(reply);
        _threadReply = string.Empty;

        // Also add to main message list and refresh thread summaries
        _messages ??= [];
        _messages.Add(reply);
        _skip++;
        BuildThreadSummaries();
    }

    private async Task OnThreadReplyKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Helpers ──

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : string.Concat(text.AsSpan(0, maxLength), "…");

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

